import { TouchableOpacity, Text, ActivityIndicator } from 'react-native';

const Button = ({ title, variant = 'primary', onPress, disabled = false, loading = false }) => {
  const variantClasses = {
    primary: 'bg-primary',
    secondary: 'bg-secondary',
    outline: 'border border-primary bg-transparent',
    danger: 'bg-red-600',
  };

  const textClasses = {
    primary: 'text-white',
    secondary: 'text-white',
    outline: 'text-primary',
    danger: 'text-white',
  };

  return (
    <TouchableOpacity
      onPress={onPress}
      disabled={disabled || loading}
      className={`py-3 px-4 rounded-lg ${variantClasses[variant]} ${disabled ? 'opacity-50' : ''}`}
    >
      {loading ? (
        <ActivityIndicator color={variant === 'outline' ? '#2E7D32' : 'white'} />
      ) : (
        <Text className={`text-center font-semibold ${textClasses[variant]}`}>
          {title}
        </Text>
      )}
    </TouchableOpacity>
  );
};

export default Button;
```
